__CPROVER_requires(__CPROVER_is_fresh(lmc->dist, sizeof(*lmc->dist)))
__CPROVER_requires(__CPROVER_is_fresh(lmc->sublen, sizeof(*lmc->sublen)))
__CPROVER_assigns()
__CPROVER_frees(lmc->length, lmc->dist, lmc->sublen)
{
    free(lmc->length);
    free(lmc->dist);
